import{_ as l,c as o,o as i,a3 as t}from"./chunks/framework.DpzXWsSh.js";const b=JSON.parse('{"title":"前端工程化 -- 自动化构建","description":"","frontmatter":{"title":"前端工程化 -- 自动化构建","date":"2024-9-15","categories":["工程化"]},"headers":[],"relativePath":"blogs/engineering/20240915.md","filePath":"blogs/engineering/20240915.md"}'),r={name:"blogs/engineering/20240915.md"},e=t('<h1 id="构建的整体设计思路" tabindex="-1">构建的整体设计思路 <a class="header-anchor" href="#构建的整体设计思路" aria-label="Permalink to &quot;构建的整体设计思路&quot;">​</a></h1><h2 id="构建工具的选择" tabindex="-1">构建工具的选择 <a class="header-anchor" href="#构建工具的选择" aria-label="Permalink to &quot;构建工具的选择&quot;">​</a></h2><p>从目前的<strong>实际业务角度</strong>去选择：</p><ul><li>UI库可以选择<code>rollup</code></li><li>小型项目可以选择<code>vite</code></li><li>大型项目可以选择<code>webpack vite</code></li><li>自己的项目也可以选择<code>turbopack、rspack、swc</code>等等</li><li>对于需要快速原型开发的项目,可以考虑使用Parcel,它的零配置特性非常适合快速启动项目。</li><li>对于大型单页应用(SPA),Next.js或Nuxt.js这样的框架也值得考虑,它们提供了开箱即用的构建优化。</li></ul><h2 id="确定构建的流程" tabindex="-1">确定构建的流程 <a class="header-anchor" href="#确定构建的流程" aria-label="Permalink to &quot;确定构建的流程&quot;">​</a></h2><ol><li><p>需要一些什么样的<code>loader</code>、<code>plugin</code>？</p></li><li><p>你所用的<code>plugin</code>、<code>loader</code>可以反映出你所设计的技术选型（css in js 、tailwind...）</p></li><li><p>举例：</p></li></ol><ul><li>如果我需要二进制文件的加载或者拷贝，我应该使用？(file-loader、url-loader、copy-webpack-plugin)</li><li>如果我需要将静态资源打包到cdn，我应该使用？(cdn-loader、cdn-plugin)</li><li>考虑使用babel-loader进行JavaScript转译,以支持新的语言特性。</li><li>对于CSS,可以考虑使用PostCSS和Autoprefixer来处理浏览器兼容性问题。</li></ul><h2 id="确定构建产物输出" tabindex="-1">确定构建产物输出 <a class="header-anchor" href="#确定构建产物输出" aria-label="Permalink to &quot;确定构建产物输出&quot;">​</a></h2><ul><li><p>我们是需要单<code>chunk</code>输出，还是多<code>chunk</code>输出？</p></li><li><p>是否需要生成<code>sourcemap</code>以便调试。</p></li><li><p>是否需要生成压缩和非压缩版本的文件。</p></li></ul><h2 id="优化打包构建流程" tabindex="-1">优化打包构建流程 <a class="header-anchor" href="#优化打包构建流程" aria-label="Permalink to &quot;优化打包构建流程&quot;">​</a></h2><ol><li><p><strong>优化打包体积</strong>？ 使用bundle分析工具(如webpack-bundle-analyzer)来可视化包大小,找出可优化的地方。</p><ol><li><strong>代码拆分（Code Splitting）</strong></li></ol><ul><li><strong>描述</strong>：将代码分割成多个小块，按需加载。提取不怎么变动的公共模块（vendor chunk）</li><li><strong>工具</strong>：Webpack 的 splitChunks、Rollup 的 output.splitting。</li><li><strong>应用场景</strong>：适用于首屏加载时间要求较高的应用。</li></ul><ol start="2"><li><strong>树摇（Tree Shaking）</strong></li></ol><ul><li><strong>描述</strong>：通过静态代码分析，去除无用的代码。</li><li><strong>工具</strong>：Webpack 支持 ES6 模块的 Tree Shaking、Rollup 的 Tree Shaking。</li><li><strong>应用场景</strong>：减少 commonjs 库的使用，尽可能使用 esm 的库,适用于使用 ES6 模块的应用。</li></ul><ol start="3"><li><strong>压缩代码</strong></li></ol><ul><li><strong>描述</strong>：压缩代码，去除空白、注释等。</li><li><strong>工具</strong>：Terser、UglifyJS、Rollup 的 terser 插件</li><li><strong>应用场景</strong>：适用于所有构建场景，尤其是生产环境</li></ul><ol start="4"><li><strong>按需加载（Lazy Loading）</strong></li></ol><ul><li><strong>描述</strong>：仅在需要时加载代码，而不是一开始就加载所有代码。</li><li><strong>工具</strong>：Webpack 的 import()、React 的 React.lazy。</li><li><strong>应用场景</strong>：适用于路由较多、功能复杂的单页应用（SPA）。</li></ul></li><li><p><strong>提升打包构建速度</strong>？</p><ol><li><strong>使用增量构建</strong></li></ol><ul><li><strong>描述</strong>：增量构建仅打包发生变化的文件，而不是每次都重新打包整个项目。</li><li><strong>工具</strong>：大多数现代构建工具（如 Webpack、Rollup）支持增量构建。</li><li><strong>应用场景</strong>：适用于开发阶段，当文件发生改动时快速反馈。</li></ul><ol start="2"><li><strong>缓存机制</strong></li></ol><ul><li><strong>描述</strong>：缓存编译结果，避免重复编译相同的代码。</li><li><strong>工具</strong>：Webpack 的 cache-loader 插件、Rollup 的 --watch 模式</li><li><strong>应用场景</strong>：适用于所有构建场景，尤其是在频繁修改代码的情况下</li></ul><ol start="2"><li><strong>优化依赖解析</strong></li></ol><ul><li><strong>描述</strong>：减少解析模块的时间，特别是在模块数量较多时。</li><li><strong>工具</strong>：Webpack 的 resolve.alias、resolve.modules。</li><li><strong>应用场景</strong>：适用于大型项目，模块依赖关系复杂的情况</li></ul><ol start="4"><li><strong>使用并行构建(多线程)</strong></li></ol><ul><li><strong>描述</strong>：利用多核 CPU 并行执行构建任务</li><li><strong>工具</strong>：Webpack 的 thread-loader、happy-pack 插件</li><li><strong>应用场景</strong>：适用于具有大量计算密集型任务的项目</li></ul><ol start="5"><li><strong>优化加载路径</strong></li></ol><ul><li><strong>描述</strong>：减少加载路径，避免不必要的文件查找</li><li><strong>工具</strong>：Webpack 的 externals、Rollup 的 external</li><li><strong>应用场景</strong>：适用于外部依赖项不需要打包的情况</li></ul></li></ol><h2 id="构建的技术选型与方案" tabindex="-1">构建的技术选型与方案 <a class="header-anchor" href="#构建的技术选型与方案" aria-label="Permalink to &quot;构建的技术选型与方案&quot;">​</a></h2>',12),n=[e];function s(a,g,c,d,u,p){return i(),o("div",null,n)}const k=l(r,[["render",s]]);export{b as __pageData,k as default};
